#include <stdio.h>
#define MOD 1000000007
int gcd(int a, int b) { return b == 0 ? a : gcd(b, a % b); }
int countArrays(int N, int M) {
    int count = 0;
    for (int mask = 0; mask < (1 << M); mask++) {
        int valid = 1;
        for (int i = 0; i < M; i++) {
            for (int j = i + 1; j < M; j++) {
                if ((mask & (1 << i)) && (mask & (1 << j)) && gcd(i + 1, j + 1) != 1) {
                    valid = 0;
                    break;
                }
            }
            if (!valid) break;
        }
        if (valid) count++;
    }
    return count;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int result = 1;
        for (int i = 0; i < N; i++) {
            result = (result * M) % MOD;
        }
        printf("%d\n", result);
    }
    return 0;
}

