import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static int gcd(int a, int b) { return b == 0 ? a : gcd(b, a % b); }
    public static int countArrays(int N, int M) {
        int count = 0;
        for (int mask = 0; mask < (1 << M); mask++) {
            int valid = 1;
            for (int i = 0; i < M; i++) {
                for (int j = i + 1; j < M; j++) {
                    if ((mask & (1 << i)) != 0 && (mask & (1 << j)) != 0 && gcd(i + 1, j + 1) != 1) {
                        valid = 0;
                        break;
                    }
                }
                if (valid == 0) break;
            }
            if (valid == 1) count++;
        }
        return count;
    }
