    if b == 0:
        return a
    return gcd(b, a % b)

def count_arrays(N, M):
    count = 0
    for mask in range(1 << M):
        valid = True
        for i in range(M):
            for j in range(i + 1, M):
                if (mask & (1 << i)) and (mask & (1 << j)) and gcd(i + 1, j + 1) != 1:
                    valid = False
                    break
            if not valid:
                break
        if valid:
            count += 1
    return count

